  ('medical-tech-moex-20868', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '嗜中性球在發炎區血管，會歷經數種生理變化，最後移行至血管外。下列各種生理現象與其負責分子之配 對中，何者正確？ rolling：ankyrin ； adhesion：integrin  rolling：integrin ； adhesion：ankyrin rolling：integrin ； adhesion：selectin  rolling：selectin ； adhesion：integrin', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "5302e461d166", "answer_pdf_sha1": "a16ccf6383bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 42, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20869', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '使用正常血漿進行混和矯正試驗時，混和後於37℃靜置2小時測試都能矯正成功，表示該檢體： 缺乏凝血因子    有凝血因子抗體 有肝素（heparin）    有紅斑性狼瘡抗凝血因子（lupus anticoagulant）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "5302e461d166", "answer_pdf_sha1": "a16ccf6383bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 43, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20870', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列何種狀況不會干擾凝血 原時間（prothrombin time）檢驗？ 肝功能異常    口服抗凝血劑 von Willebrand氏症    狼瘡抗凝血抗體（lupus anticoagulant）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "5302e461d166", "answer_pdf_sha1": "a16ccf6383bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 44, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20871', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', 'INR（international normalized ratio）之報告方式最適用於下列何者？ 吃口服抗凝血劑的病人追蹤用  診斷血液凝固因子異常 診斷血小板功能異常    施打肝素之病人追蹤用', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "5302e461d166", "answer_pdf_sha1": "a16ccf6383bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 45, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20872', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '瀰漫性血管內凝固（disseminated intravascular coagulation）之特性，下列何者錯誤？ 血小板功能會受影響 活化部分凝血質時間（activated partial thromboplastin time）會延長 凝血 原時間（prothrombin time）會延長 會產生血栓，但不會出血', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "5302e461d166", "answer_pdf_sha1": "a16ccf6383bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 46, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20873', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '活化部分凝血質時間（activated partial thromboplastin time）之檢測容易受到干擾，則下列何者正確？ 溶血檢體會縮短活化部分凝血質時間  抗凝劑比例太高時會縮短活化部分凝血質時間 肝素（heparin）污染會縮短活化部分凝血質時間  血小板污染會延長活化部分凝血質時間', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "5302e461d166", "answer_pdf_sha1": "a16ccf6383bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 47, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
